+        --expt-relaxed-constexpr
+        --use_fast_math
+        --disable-warnings
+    >
+    $<$<COMPILE_LANGUAGE:CXX>:-w>
+)
+target_link_libraries(_kernels PRIVATE ${TORCH_LIBRARIES} Python::Python pybind11::module ${TORCH_PYTHON_LIBRARY})
